"use client";

import { useMemo } from "react";
import { cn } from "@/lib/utils";
import { InfiniteLoader } from "./parts/infinite-loader";
import { MagazineTower } from "./parts/magazine-tower";
import {
  DEFAULT_GRID_LABELS,
  type GridLayoutNewsProps,
} from "./types";

/**
 * GridLayoutNews01 — slot-based magazine layout. Composes the news-domain
 * components (page-hero / filter-bar / content-cards / category-cloud /
 * newsletter-card) at the consumer level via slots; the layout itself
 * imports none of them at runtime.
 *
 * Generic over `T` — the item shape. Pair with `useMagazineFilter` for
 * filter + page state, or drive `displayedItems` / `featuredItem` /
 * `hasMore` / `isLoading` / `onLoadMore` directly.
 */
export function GridLayoutNews01<T>(props: GridLayoutNewsProps<T>) {
  const {
    displayedItems,
    featuredItem,
    hasMore = false,
    isLoading = false,
    onLoadMore,
    renderItem,
    renderFeatured,
    hero,
    filterBar,
    sidebar,
    emptyState,
    labels: labelsProp,
    className,
    mainClassName,
    sidebarClassName,
  } = props;

  const labels = useMemo(
    () => ({ ...DEFAULT_GRID_LABELS, ...labelsProp }),
    [labelsProp],
  );

  const hasContent = displayedItems.length > 0 || featuredItem !== undefined;
  const isEmpty = !hasContent && !isLoading;

  const showSidebar = sidebar !== undefined;

  return (
    <div className={cn("w-full", className)}>
      {hero ? <div className="mb-12">{hero}</div> : null}

      {filterBar ? <div className="mb-8">{filterBar}</div> : null}

      {isEmpty ? (
        <div className="py-20 text-center">
          {emptyState ?? (
            <p className="text-muted-foreground">{labels.emptyStateText}</p>
          )}
        </div>
      ) : (
        <div className="grid grid-cols-12 gap-6">
          <div
            className={cn(
              "space-y-8",
              showSidebar ? "col-span-12 lg:col-span-8" : "col-span-12",
              mainClassName,
            )}
          >
            {featuredItem !== undefined ? (
              <div>
                {renderFeatured
                  ? renderFeatured(featuredItem)
                  : renderItem(featuredItem, "large")}
              </div>
            ) : null}

            <MagazineTower items={displayedItems} renderItem={renderItem} />

            <InfiniteLoader
              hasMore={hasMore}
              isLoading={isLoading}
              onLoadMore={onLoadMore}
              hasItems={hasContent}
              labels={labels}
            />
          </div>

          {showSidebar ? (
            <aside
              className={cn(
                "col-span-12 lg:col-span-4",
                sidebarClassName,
              )}
            >
              <div className="sticky top-24 space-y-8">{sidebar}</div>
            </aside>
          ) : null}
        </div>
      )}
    </div>
  );
}

export default GridLayoutNews01;

export { GridLayoutNews01, default } from "./grid-layout-news-01";
export { useMagazineFilter } from "./hooks/use-magazine-filter";
export { useInfiniteScroll } from "./hooks/use-infinite-scroll";
export type {
  GridLayoutItemSlot,
  GridLayoutLabels,
  GridLayoutNewsProps,
  UseMagazineFilterArgs,
  UseMagazineFilterReturn,
} from "./types";
export { meta } from "./meta";

import type { ReactNode } from "react";

/**
 * Slot identifier passed to `renderItem`. The layout always renders one
 * or more `medium` slots; `large` is the lead slot in the main column
 * when there are enough items.
 */
export type GridLayoutItemSlot = "large" | "medium";

export interface GridLayoutLabels {
  /** Visually-hidden loader announcement. Default: 'Loading more items…'. */
  loadingLabel?: string;
  /** Terminal end-of-list text. Default: 'All items shown'. */
  endOfListText?: string;
  /** Default empty-state body when `emptyState` slot is not provided. Default: 'No items to show.'. */
  emptyStateText?: string;
}

export interface GridLayoutNewsProps<T> {
  /** Current page of items (filtered + paged by the consumer or `useMagazineFilter`). */
  displayedItems: T[];
  /** Optional featured item rendered above the main column on page 1. */
  featuredItem?: T;

  /** Whether more items are available beyond the current page. */
  hasMore?: boolean;
  /** Whether `onLoadMore` is currently fetching. */
  isLoading?: boolean;
  /** Callback fired when the loader sentinel enters the viewport. */
  onLoadMore?: () => void;

  /** How to render one item in a given slot. */
  renderItem: (item: T, slot: GridLayoutItemSlot) => ReactNode;
  /** How to render the featured item. Defaults to `renderItem(featuredItem, 'large')`. */
  renderFeatured?: (item: T) => ReactNode;

  /** Optional hero band rendered full-width above the filter bar. */
  hero?: ReactNode;
  /** Optional filter bar rendered above the grid. */
  filterBar?: ReactNode;
  /** Optional sidebar rendered to the right (col-span-4) of the main column. */
  sidebar?: ReactNode;

  /** Optional empty-state node. Rendered when displayedItems is empty AND not loading. */
  emptyState?: ReactNode;

  labels?: GridLayoutLabels;
  className?: string;
  mainClassName?: string;
  sidebarClassName?: string;
}

export const DEFAULT_GRID_LABELS: Required<GridLayoutLabels> = {
  loadingLabel: "Loading more items…",
  endOfListText: "All items shown",
  emptyStateText: "No items to show.",
};

export interface UseMagazineFilterArgs<T> {
  /** Source items (consumer's full dataset). */
  items: T[];
  /** Per-page size. Default: 6. */
  pageSize?: number;
  /** Predicate to derive the featured item (returns true for the one to feature on page 1). */
  isFeatured?: (item: T) => boolean;
  /** Filter / search predicate. Default: include everything. */
  filterPredicate?: (item: T) => boolean;
  /** Sort comparator. Default: no sort. */
  sortComparator?: (a: T, b: T) => number;
  /** Artificial loading delay in ms (for demos). Default: 0. */
  simulatedLoadingMs?: number;
}

export interface UseMagazineFilterReturn<T> {
  displayedItems: T[];
  featuredItem: T | undefined;
  hasMore: boolean;
  isLoading: boolean;
  filteredCount: number;
  loadMore: () => void;
  reset: () => void;
}

import type { ReactNode } from "react";
import type { GridLayoutItemSlot } from "../types";

/**
 * The main column's "tower" of cards: 1 large card on top, 2-up medium row,
 * then a 3-up grid of remaining medium cards. The descending-density
 * pattern is the magazine intuition baked in.
 *
 * If there are 1 or 2 items, the layout adapts: one item = just the large;
 * two items = large + a single medium row.
 */
export function MagazineTower<T>({
  items,
  renderItem,
}: {
  items: T[];
  renderItem: (item: T, slot: GridLayoutItemSlot) => ReactNode;
}) {
  if (items.length === 0) return null;

  const lead = items[0];
  const twoUp = items.slice(1, 3);
  const rest = items.slice(3);

  return (
    <div className="space-y-8">
      {renderItem(lead, "large")}

      {twoUp.length > 0 ? (
        <div className="grid gap-6 md:grid-cols-2">
          {twoUp.map((item, i) => (
            <div key={i}>{renderItem(item, "medium")}</div>
          ))}
        </div>
      ) : null}

      {rest.length > 0 ? (
        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
          {rest.map((item, i) => (
            <div key={i}>{renderItem(item, "medium")}</div>
          ))}
        </div>
      ) : null}
    </div>
  );
}

"use client";

import { useRef } from "react";
import { cn } from "@/lib/utils";
import { useInfiniteScroll } from "../hooks/use-infinite-scroll";
import type { GridLayoutLabels } from "../types";

/**
 * Loader region. Holds the IntersectionObserver sentinel + visible status:
 *
 * - Loading → 3 bouncing dots (visually) + visually-hidden text label in
 *   an `aria-live="polite"` region.
 * - End-of-list (no more items, but at least one rendered) → muted text
 *   announcing completion.
 * - Otherwise → invisible sentinel only.
 */
export function InfiniteLoader({
  hasMore,
  isLoading,
  onLoadMore,
  hasItems,
  labels,
}: {
  hasMore: boolean;
  isLoading: boolean;
  onLoadMore: (() => void) | undefined;
  hasItems: boolean;
  labels: Required<GridLayoutLabels>;
}) {
  const sentinelRef = useRef<HTMLDivElement>(null);
  useInfiniteScroll({
    ref: sentinelRef,
    hasMore,
    isLoading,
    onLoadMore,
  });

  const showEndOfList = !hasMore && hasItems && !isLoading;

  return (
    <div ref={sentinelRef} className="flex justify-center py-8">
      {isLoading ? (
        <div
          aria-live="polite"
          className="flex items-center gap-3"
        >
          <span className="sr-only">{labels.loadingLabel}</span>
          {[0, 1, 2].map((i) => (
            <span
              key={i}
              aria-hidden="true"
              className={cn(
                "h-2 w-2 rounded-full bg-primary",
                "motion-safe:animate-bounce",
              )}
              style={{ animationDelay: `${-300 + i * 150}ms` }}
            />
          ))}
        </div>
      ) : null}

      {showEndOfList ? (
        <p
          aria-live="polite"
          className="text-sm text-muted-foreground"
        >
          {labels.endOfListText}
        </p>
      ) : null}
    </div>
  );
}

"use client";

import { useEffect, type RefObject } from "react";

/**
 * Wires an IntersectionObserver to a sentinel element. When the sentinel
 * enters the viewport AND `hasMore` is true AND `isLoading` is false,
 * `onLoadMore` is fired.
 */
export function useInfiniteScroll({
  ref,
  hasMore,
  isLoading,
  onLoadMore,
  threshold = 0.1,
}: {
  ref: RefObject<HTMLDivElement | null>;
  hasMore: boolean;
  isLoading: boolean;
  onLoadMore: (() => void) | undefined;
  threshold?: number;
}) {
  useEffect(() => {
    const sentinel = ref.current;
    if (!sentinel) return;
    if (!onLoadMore) return;

    const observer = new IntersectionObserver(
      (entries) => {
        if (entries[0].isIntersecting && hasMore && !isLoading) {
          onLoadMore();
        }
      },
      { threshold },
    );

    observer.observe(sentinel);
    return () => observer.disconnect();
  }, [ref, hasMore, isLoading, onLoadMore, threshold]);
}

"use client";

import { useCallback, useMemo, useState } from "react";
import type {
  UseMagazineFilterArgs,
  UseMagazineFilterReturn,
} from "../types";

/**
 * Companion hook for the simple consumer who wants filter + sort + paging
 * + loading state without writing it from scratch. Sophisticated consumers
 * skip this and drive the layout's props directly.
 *
 * Reset semantics: any change to `items`, `filterPredicate`, or
 * `sortComparator` reference resets the page back to 1.
 */
export function useMagazineFilter<T>({
  items,
  pageSize = 6,
  isFeatured,
  filterPredicate,
  sortComparator,
  simulatedLoadingMs = 0,
}: UseMagazineFilterArgs<T>): UseMagazineFilterReturn<T> {
  const [page, setPage] = useState(1);
  const [isLoading, setIsLoading] = useState(false);

  const sortedFiltered = useMemo(() => {
    let result = filterPredicate ? items.filter(filterPredicate) : items.slice();
    if (sortComparator) result = result.sort(sortComparator);
    return result;
  }, [items, filterPredicate, sortComparator]);

  const featuredItem = useMemo(() => {
    if (!isFeatured) return undefined;
    return sortedFiltered.find(isFeatured);
  }, [sortedFiltered, isFeatured]);

  const regularItems = useMemo(
    () =>
      featuredItem
        ? sortedFiltered.filter((item) => item !== featuredItem)
        : sortedFiltered,
    [sortedFiltered, featuredItem],
  );

  const displayedItems = useMemo(
    () => regularItems.slice(0, page * pageSize),
    [regularItems, page, pageSize],
  );

  const hasMore = displayedItems.length < regularItems.length;
  const filteredCount = sortedFiltered.length;

  const loadMore = useCallback(() => {
    if (isLoading || !hasMore) return;
    if (simulatedLoadingMs > 0) {
      setIsLoading(true);
      setTimeout(() => {
        setPage((p) => p + 1);
        setIsLoading(false);
      }, simulatedLoadingMs);
    } else {
      setPage((p) => p + 1);
    }
  }, [isLoading, hasMore, simulatedLoadingMs]);

  const reset = useCallback(() => {
    setPage(1);
    setIsLoading(false);
  }, []);

  return {
    displayedItems,
    featuredItem: page === 1 ? featuredItem : undefined,
    hasMore,
    isLoading,
    filteredCount,
    loadMore,
    reset,
  };
}
